@component.add(
    name="The month when tree growth begins",
    units="сар",
    comp_type="Constant",
    comp_subtype="Normal",
)
def the_month_when_tree_growth_begins():
    return 5


@component.add(
    name="The month when tree growth stops",
    units="сар",
    comp_type="Constant",
    comp_subtype="Normal",
)
def the_month_when_tree_growth_stops():
    return 9


@component.add(
    name="The normal growth period of a tree",
    units="сар",
    comp_type="Auxiliary",
    comp_subtype="Normal",
    depends_on={
        "the_month_when_tree_growth_stops": 1,
        "the_month_when_tree_growth_begins": 1,
    },
)
def the_normal_growth_period_of_a_tree():
    """
    typical time needed for this crop to mature
    """
    return the_month_when_tree_growth_stops() - the_month_when_tree_growth_begins()


@component.add(
    name="Natural forest average age",
    units="Жил",
    subscripts=["Модны төрөл"],
    comp_type="Auxiliary",
    comp_subtype="Normal",
    depends_on={
        "time": 2,
        "natural_forest_average_age_in_2020_by_tree_type": 2,
        "increase_in_life_expectancy": 1,
    },
)
def natural_forest_average_age():
    return if_then_else(
        time() == 2020,
        lambda: natural_forest_average_age_in_2020_by_tree_type(),
        lambda: natural_forest_average_age_in_2020_by_tree_type()
        + increase_in_life_expectancy(time()),
    )


