@component.add(
    name="Байгалийн ойн 1 гагын мөчрийн ургалтын чадамж",
    units="м куб/(га*сар)",
    subscripts=["Модны төрөл"],
    comp_type="Auxiliary",
    comp_subtype="Normal",
    depends_on={
        "natural_forest_average_diameter_at_breast_height": 16,
        "soil_moisture_ratio": 6,
        "natural_forest_average_height": 6,
        "the_normal_growth_period_of_a_tree": 6,
    },
)
def nvs_1__64():
    """
    crop A production potential IF THEN ELSE(температурын өөрчлөлт>-10 :OR: температурын өөрчлөлт<-5, Буудайн гагаас авсан хамгийн их ургацын хэмжээ/(Буудайн боловсорч гүйцэхэд шаардлагатай ердийн хугацаа )*Буудайн харьцангуй ургацын хэмжээ хөрсний чийгээс хамаарсан(хөрсний чийгийн харьцаа ),0)
    """
    value = xr.DataArray(
        np.nan, {"Модны төрөл": _subscript_dict["Модны төрөл"]}, ["Модны төрөл"]
    )
    value.loc[["Сибирь шинэс"]] = if_then_else(
        np.logical_and(
            float(
                natural_forest_average_diameter_at_breast_height().loc["Сибирь шинэс"]
            )
            > 6,
            float(
                natural_forest_average_diameter_at_breast_height().loc["Сибирь шинэс"]
            )
            <= 15,
        ),
        lambda: (
            float(
                np.exp(
                    -3.06
                    + 3.263
                    * float(
                        np.log(
                            float(
                                natural_forest_average_diameter_at_breast_height().loc[
                                    "Сибирь шинэс"
                                ]
                            )
                            / 10
                        )
                    )
                    - 1.474
                    * float(
                        np.log(
                            float(natural_forest_average_height().loc["Сибирь шинэс"])
                        )
                    )
                )
            )
            * soil_moisture_ratio()
        )
        * 339
        / the_normal_growth_period_of_a_tree(),
        lambda: if_then_else(
            np.logical_and(
                float(
                    natural_forest_average_diameter_at_breast_height().loc[
                        "Сибирь шинэс"
                    ]
                )
                > 15,
                float(
                    natural_forest_average_diameter_at_breast_height().loc[
                        "Сибирь шинэс"
                    ]
                )
                <= 30,
            ),
            lambda: (
                float(
                    np.exp(
                        -3.06
                        + 3.263
                        * float(
                            np.log(
                                float(
                                    natural_forest_average_diameter_at_breast_height().loc[
                                        "Сибирь шинэс"
                                    ]
                                )
                                / 10
                            )
                        )
                        - 1.474
                        * float(
                            np.log(
                                float(
                                    natural_forest_average_height().loc["Сибирь шинэс"]
                                )
                            )
                        )
                    )
                )
                * soil_moisture_ratio()
            )
            * 168
            / the_normal_growth_period_of_a_tree(),
            lambda: if_then_else(
                float(
                    natural_forest_average_diameter_at_breast_height().loc[
                        "Сибирь шинэс"
                    ]
                )
                > 30,
                lambda: (
                    float(
                        np.exp(
                            -3.06
                            + 3.263
                            * float(
                                np.log(
                                    float(
                                        natural_forest_average_diameter_at_breast_height().loc[
                                            "Сибирь шинэс"
                                        ]
                                    )
                                    / 10
                                )
                            )
                            - 1.474
                            * float(
                                np.log(
                                    float(
                                        natural_forest_average_height().loc[
                                            "Сибирь шинэс"
                                        ]
                                    )
                                )
                            )
                        )
                    )
                    * soil_moisture_ratio()
                )
                * 53
                / the_normal_growth_period_of_a_tree(),
                lambda: 0,
            ),
        ),
    )
    value.loc[["Ойн нарс"]] = if_then_else(
        np.logical_and(
            float(natural_forest_average_diameter_at_breast_height().loc["Ойн нарс"])
            > 6,
            float(natural_forest_average_diameter_at_breast_height().loc["Ойн нарс"])
            <= 15,
        ),
        lambda: (
            float(
                np.exp(
                    -4.705
                    + 2.388
                    * float(
                        np.log(
                            (
                                float(
                                    natural_forest_average_diameter_at_breast_height().loc[
                                        "Ойн нарс"
                                    ]
                                )
                                / 10
                            )
                            ** 2
                            * float(natural_forest_average_height().loc["Ойн нарс"])
                        )
                    )
                )
            )
            * soil_moisture_ratio()
        )
        * 339
        / the_normal_growth_period_of_a_tree(),
        lambda: if_then_else(
            np.logical_and(
                float(
                    natural_forest_average_diameter_at_breast_height().loc["Ойн нарс"]
                )
                > 15,
                float(
                    natural_forest_average_diameter_at_breast_height().loc["Ойн нарс"]
                )
                <= 30,
            ),
            lambda: (
                float(
                    np.exp(
                        -4.705
                        + 2.388
                        * float(
                            np.log(
                                (
                                    float(
                                        natural_forest_average_diameter_at_breast_height().loc[
                                            "Ойн нарс"
                                        ]
                                    )
                                    / 10
                                )
                                ** 2
                                * float(natural_forest_average_height().loc["Ойн нарс"])
                            )
                        )
                    )
                )
                * soil_moisture_ratio()
            )
            * 168
            / the_normal_growth_period_of_a_tree(),
            lambda: if_then_else(
                float(
                    natural_forest_average_diameter_at_breast_height().loc["Ойн нарс"]
                )
                > 30,
                lambda: (
                    float(
                        np.exp(
                            -4.705
                            + 2.388
                            * float(
                                np.log(
                                    (
                                        float(
                                            natural_forest_average_diameter_at_breast_height().loc[
                                                "Ойн нарс"
                                            ]
                                        )
                                        / 10
                                    )
                                    ** 2
                                    * float(
                                        natural_forest_average_height().loc["Ойн нарс"]
                                    )
                                )
                            )
                        )
                    )
                    * soil_moisture_ratio()
                )
                * 53
                / the_normal_growth_period_of_a_tree(),
                lambda: 0,
            ),
        ),
    )
    return value


