@component.add(
    name="Тарьсан 1ш модны шилүүсний ургалт",
    units="м куб",
    subscripts=["Модны төрөл"],
    comp_type="Auxiliary",
    comp_subtype="Normal",
    depends_on={"time": 2, "nvs__753": 2, "nvs__707": 2, "nvs__702": 2},
)
def nvs_1__67():
    """
    crop A production potential IF THEN ELSE(температурын өөрчлөлт>-10 :OR: температурын өөрчлөлт<-5, Буудайн гагаас авсан хамгийн их ургацын хэмжээ/(Буудайн боловсорч гүйцэхэд шаардлагатай ердийн хугацаа )*Буудайн харьцангуй ургацын хэмжээ хөрсний чийгээс хамаарсан(хөрсний чийгийн харьцаа ),0)
    """
    value = xr.DataArray(
        np.nan, {"Модны төрөл": _subscript_dict["Модны төрөл"]}, ["Модны төрөл"]
    )
    value.loc[["Сибирь шинэс"]] = if_then_else(
        time() < nvs__753(),
        lambda: 0,
        lambda: float(
            np.exp(
                -3.701
                + 2.736 * float(np.log(float(nvs__702().loc["Сибирь шинэс"]) / 10))
                - 1.315 * float(np.log(float(nvs__707().loc["Сибирь шинэс"])))
            )
        ),
    )
    value.loc[["Ойн нарс"]] = if_then_else(
        time() < nvs__753(),
        lambda: 0,
        lambda: float(
            np.exp(
                -4.03
                + 2.003
                * float(
                    np.log(
                        (float(nvs__702().loc["Ойн нарс"]) / 10) ** 2
                        * float(nvs__707().loc["Ойн нарс"])
                    )
                )
            )
        ),
    )
    return value


