@component.add(
    name="Natural forest average height",
    units="м",
    subscripts=["Модны төрөл"],
    comp_type="Auxiliary",
    comp_subtype="Normal",
    depends_on={"natural_forest_average_diameter_at_breast_height": 12},
)
def natural_forest_average_height():
    """
    15-70 насны ойд ч энэ зүй тогтол ажиглагдах бөгөөд тухайлбал: 15 настай шинэсэн ойн дундаж өндөр 3.8 м, 28 настай ойнх 7.9 м, 31 настай ойнх 9.5 м, 38 настай ойнх 15.4 м, 70 настай ойнх 18.1 м тус тус байв
    """
    value = xr.DataArray(
        np.nan, {"Модны төрөл": _subscript_dict["Модны төрөл"]}, ["Модны төрөл"]
    )
    value.loc[["Сибирь шинэс"]] = (
        2.0273
        * float(natural_forest_average_diameter_at_breast_height().loc["Сибирь шинэс"])
        ** 0.6215
    )
    value.loc[["Ойн нарс"]] = (
        2.1209
        * float(natural_forest_average_diameter_at_breast_height().loc["Ойн нарс"])
        ** 0.6157
    )
    value.loc[["Сибирь хуш"]] = (
        1.7843
        * float(natural_forest_average_diameter_at_breast_height().loc["Сибирь хуш"])
        ** 0.6328
    )
    value.loc[["Гацуур"]] = (
        1.5364
        * float(natural_forest_average_diameter_at_breast_height().loc["Гацуур"])
        ** 0.7165
    )
    value.loc[["Жодоо"]] = (
        2.2508
        * float(natural_forest_average_diameter_at_breast_height().loc["Жодоо"])
        ** 0.6159
    )
    value.loc[["Хавтага навчит хус"]] = (
        1.747
        * float(
            natural_forest_average_diameter_at_breast_height().loc["Хавтага навчит хус"]
        )
        ** 0.677
    )
    value.loc[["Анхилуун улиас"]] = (
        1.319
        * float(
            natural_forest_average_diameter_at_breast_height().loc["Анхилуун улиас"]
        )
        ** 0.7144
    )
    value.loc[["Улиангар"]] = (
        1.953
        * float(natural_forest_average_diameter_at_breast_height().loc["Улиангар"])
        ** 0.6525
    )
    value.loc[["Хайлаас"]] = (
        1.199
        * float(natural_forest_average_diameter_at_breast_height().loc["Хайлаас"])
        ** 0.5813
    )
    value.loc[["Бургас"]] = (
        1.9222
        * float(natural_forest_average_diameter_at_breast_height().loc["Бургас"])
        ** 0.4858
    )
    value.loc[["Заг"]] = (
        1.7179
        * float(natural_forest_average_diameter_at_breast_height().loc["Заг"]) ** 0.6792
    )
    value.loc[["Тоорой"]] = (
        1.7179
        * float(natural_forest_average_diameter_at_breast_height().loc["Тоорой"])
        ** 0.6792
    )
    return value


