@component.add(
    name="Тарьсан ойн 1ш модны мөчрийн ургалт",
    units="м куб/(сар)",
    subscripts=["Модны төрөл"],
    comp_type="Auxiliary",
    comp_subtype="Normal",
    depends_on={
        "in_year": 4,
        "the_month_when_tree_growth_begins": 2,
        "the_month_when_tree_growth_stops": 2,
        "nvs_1__73": 2,
    },
)
def nvs_1__72():
    """
    Actual crop production only occurs during the time when the crop is in the ground.
    """
    value = xr.DataArray(
        np.nan, {"Модны төрөл": _subscript_dict["Модны төрөл"]}, ["Модны төрөл"]
    )
    value.loc[["Сибирь шинэс"]] = if_then_else(
        np.logical_or(
            in_year() < the_month_when_tree_growth_begins(),
            in_year() > the_month_when_tree_growth_stops(),
        ),
        lambda: 0,
        lambda: float(nvs_1__73().loc["Сибирь шинэс"]),
    )
    value.loc[["Ойн нарс"]] = if_then_else(
        np.logical_or(
            in_year() < the_month_when_tree_growth_begins(),
            in_year() > the_month_when_tree_growth_stops(),
        ),
        lambda: 0,
        lambda: float(nvs_1__73().loc["Ойн нарс"]),
    )
    return value


@component.add(
    name="Тарьсан ойн 1ш модны мөчрийн ургалтын чадамж",
    units="м куб/(сар)",
    subscripts=["Модны төрөл"],
    comp_type="Auxiliary",
    comp_subtype="Normal",
    depends_on={
        "nvs_1__68": 2,
        "soil_moisture_ratio": 2,
        "the_normal_growth_period_of_a_tree": 2,
    },
)
def nvs_1__73():
    """
    crop A production potential IF THEN ELSE(температурын өөрчлөлт>-10 :OR: температурын өөрчлөлт<-5, Буудайн гагаас авсан хамгийн их ургацын хэмжээ/(Буудайн боловсорч гүйцэхэд шаардлагатай ердийн хугацаа )*Буудайн харьцангуй ургацын хэмжээ хөрсний чийгээс хамаарсан(хөрсний чийгийн харьцаа ),0)
    """
    value = xr.DataArray(
        np.nan, {"Модны төрөл": _subscript_dict["Модны төрөл"]}, ["Модны төрөл"]
    )
    value.loc[["Сибирь шинэс"]] = (
        float(nvs_1__68().loc["Сибирь шинэс"])
        * soil_moisture_ratio()
        / the_normal_growth_period_of_a_tree()
    )
    value.loc[["Ойн нарс"]] = (
        float(nvs_1__68().loc["Ойн нарс"])
        * soil_moisture_ratio()
        / the_normal_growth_period_of_a_tree()
    )
    return value


